/**
 * Deploy a simple TEST_Token ERC20 on Base Sepolia
 *
 * Prerequisites:
 * 1. Set PRIVATE_KEY environment variable with your deployer wallet private key
 * 2. Ensure you have testnet ETH on Base Sepolia for gas
 *
 * Usage:
 *   PRIVATE_KEY=0x... npm run deploy-token
 */

import { createPublicClient, createWalletClient, http, encodeDeployData } from 'viem';
import { privateKeyToAccount } from 'viem/accounts';
import { baseSepolia } from 'viem/chains';

// Simple ERC20 bytecode and ABI
// This is a minimal ERC20 implementation for testing purposes
const ERC20_BYTECODE =
  '' as const;

const ERC20_ABI = [
  {
    type: 'constructor',
    inputs: [
      { name: 'name_', type: 'string' },
      { name: 'symbol_', type: 'string' },
      { name: 'decimals_', type: 'uint8' },
      { name: 'totalSupply_', type: 'uint256' },
    ],
  },
  {
    name: 'Transfer',
    type: 'event',
    inputs: [
      { name: 'from', type: 'address', indexed: true },
      { name: 'to', type: 'address', indexed: true },
      { name: 'value', type: 'uint256', indexed: false },
    ],
  },
  {
    name: 'Approval',
    type: 'event',
    inputs: [
      { name: 'owner', type: 'address', indexed: true },
      { name: 'spender', type: 'address', indexed: true },
      { name: 'value', type: 'uint256', indexed: false },
    ],
  },
  {
    name: 'name',
    type: 'function',
    stateMutability: 'view',
    inputs: [],
    outputs: [{ name: '', type: 'string' }],
  },
  {
    name: 'symbol',
    type: 'function',
    stateMutability: 'view',
    inputs: [],
    outputs: [{ name: '', type: 'string' }],
  },
  {
    name: 'decimals',
    type: 'function',
    stateMutability: 'view',
    inputs: [],
    outputs: [{ name: '', type: 'uint8' }],
  },
  {
    name: 'totalSupply',
    type: 'function',
    stateMutability: 'view',
    inputs: [],
    outputs: [{ name: '', type: 'uint256' }],
  },
  {
    name: 'balanceOf',
    type: 'function',
    stateMutability: 'view',
    inputs: [{ name: 'account', type: 'address' }],
    outputs: [{ name: '', type: 'uint256' }],
  },
  {
    name: 'transfer',
    type: 'function',
    stateMutability: 'nonpayable',
    inputs: [
      { name: 'to', type: 'address' },
      { name: 'amount', type: 'uint256' },
    ],
    outputs: [{ name: '', type: 'bool' }],
  },
  {
    name: 'approve',
    type: 'function',
    stateMutability: 'nonpayable',
    inputs: [
      { name: 'spender', type: 'address' },
      { name: 'amount', type: 'uint256' },
    ],
    outputs: [{ name: '', type: 'bool' }],
  },
] as const;

// Token configuration
const TOKEN_CONFIG = {
  name: 'TEST_Token',
  symbol: 'TEST',
  decimals: 18,
  totalSupply: 1_000_000_000n * 10n ** 18n, // 1 billion tokens
};

async function main() {
  // Validate environment
  const privateKey = process.env.PRIVATE_KEY;

  if (!privateKey) {
    console.error('Error: PRIVATE_KEY environment variable is required');
    console.error('Usage: PRIVATE_KEY=0x... npm run deploy-token');
    process.exit(1);
  }

  // Setup clients
  const account = privateKeyToAccount(privateKey as `0x${string}`);
  console.log(`Deployer address: ${account.address}`);

  const publicClient = createPublicClient({
    chain: baseSepolia,
    transport: http(),
  });

  const walletClient = createWalletClient({
    account,
    chain: baseSepolia,
    transport: http(),
  });

  // Check deployer balance
  const balance = await publicClient.getBalance({ address: account.address });
  console.log(`ETH balance: ${balance.toString()} wei`);

  if (balance === 0n) {
    console.error('Error: No ETH balance. Get testnet ETH from a faucet.');
    console.error(
      'Base Sepolia faucet: https://www.coinbase.com/faucets/base-ethereum-sepolia-faucet'
    );
    process.exit(1);
  }

  console.log(`\nDeploying ${TOKEN_CONFIG.name} (${TOKEN_CONFIG.symbol})...`);
  console.log(
    `Total supply: ${TOKEN_CONFIG.totalSupply.toString()} (${
      TOKEN_CONFIG.totalSupply / 10n ** 18n
    } tokens)`
  );

  // Deploy contract
  const deployData = encodeDeployData({
    abi: ERC20_ABI,
    bytecode: ERC20_BYTECODE,
    args: [TOKEN_CONFIG.name, TOKEN_CONFIG.symbol, TOKEN_CONFIG.decimals, TOKEN_CONFIG.totalSupply],
  });

  const hash = await walletClient.sendTransaction({
    data: deployData,
  });

  console.log(`Deploy tx: ${hash}`);

  const receipt = await publicClient.waitForTransactionReceipt({ hash });
  const tokenAddress = receipt.contractAddress;

  console.log('\n========================================');
  console.log('TOKEN DEPLOYED SUCCESSFULLY!');
  console.log('========================================');
  console.log(`Token Address: ${tokenAddress}`);
  console.log(`Name: ${TOKEN_CONFIG.name}`);
  console.log(`Symbol: ${TOKEN_CONFIG.symbol}`);
  console.log(`Decimals: ${TOKEN_CONFIG.decimals}`);
  console.log(`Total Supply: ${TOKEN_CONFIG.totalSupply / 10n ** 18n} ${TOKEN_CONFIG.symbol}`);
  console.log('========================================');
  console.log('\nNext steps:');
  console.log(`1. Deploy CCA: PRIVATE_KEY=0x... TOKEN_ADDRESS=${tokenAddress} npm run deploy-cca`);
  console.log('\nView on BaseScan:');
  console.log(`https://sepolia.basescan.org/token/${tokenAddress}`);
}

main().catch(console.error);
